public void toString(StringBuilder buf) {
    if (Modifier.isPublic(modifiers)) {
        buf.append("\tpublic ");
    }

    if ("<init>".equals(name)) {
        buf.append(classWriter.name);
    } else {
        buf.append(getTypeName(returnType)).append(' ').append(name);
    }

    boolean newLine = paramTypes.length > 3;
    buf.append('(');
    if (newLine) {
        buf.append("\n\t\t\t");
    }

    for (int i = 0; i < paramTypes.length; i++) {
        if (i != 0) {
            if (newLine) {
                buf.append(",\n\t\t\t");
            } else {
                buf.append(", ");
            }
        }
        Class paramType = paramTypes[i];
        String paramName = paramNames[i];
        buf.append(getTypeName(paramType)).append(' ').append(paramName);
    }

    if (newLine) {
        buf.append("\n\t");
    }

    buf.append(") {\n");

    for (int i = 0; i < statements.size(); i++) {
        if (i != 0) {
            buf.append('\n');
        }
        Statement stmt = statements.get(i);
        stmt.toString(this, buf, 2);
    }

    buf.append("\n\t}");
}

public void visitVarInsn(final int opcode, final int var) {
    lastBytecodeOffset = code.length;
    // Add the instruction to the bytecode of the method.
    if (var < 4 && opcode != Opcodes.RET) {
        int optimizedOpcode;
        if (opcode < Opcodes.ISTORE) {
            optimizedOpcode = Constants.ILOAD_0 + ((opcode - Opcodes.ILOAD) << 2) + var;
        } else {
            optimizedOpcode = Constants.ISTORE_0 + ((opcode - Opcodes.ISTORE) << 2) + var;
        }
        code.putByte(optimizedOpcode);
    } else if (var >= 256) {
        code.putByte(Constants.WIDE).put12(opcode, var);
    } else {
        code.put11(opcode, var);
    }
    // If needed, update the maximum stack size and number of locals, and stack map frames.
    if (currentBasicBlock != null) {
        currentBasicBlock.frame.execute(opcode, var, null, null);
    }

    int currentMaxLocals;
    if (opcode == Opcodes.LLOAD
            || opcode == Opcodes.DLOAD
            || opcode == Opcodes.LSTORE
            || opcode == Opcodes.DSTORE) {
        currentMaxLocals = var + 2;
    } else {
        currentMaxLocals = var + 1;
    }
    if (currentMaxLocals > maxLocals) {
        maxLocals = currentMaxLocals;
    }
}

static int writeTypeName(byte[] bytes, int off, String typeName, JSONWriter jsonWriter) {
    JSONWriterJSONB jsonWriterJSONB = (JSONWriterJSONB) jsonWriter;
    SymbolTable symbolTable = jsonWriter.symbolTable;
    bytes[off++] = BC_TYPED_ANY;

    long hash = Fnv.hashCode64(typeName);

    int symbol = -1;
    if (symbolTable != null) {
        symbol = symbolTable.getOrdinalByHashCode(hash);
        if (symbol == -1 && jsonWriterJSONB.symbols != null) {
            symbol = jsonWriterJSONB.symbols.get(hash);
        }
    } else if (jsonWriterJSONB.symbols != null) {
        symbol = jsonWriterJSONB.symbols.get(hash);
    }

    if (symbol == -1) {
        if (jsonWriterJSONB.symbols == null) {
            jsonWriterJSONB.symbols = new TLongIntHashMap();
        }
        jsonWriterJSONB.symbols.put(hash, symbol = jsonWriterJSONB.symbolIndex++);
    } else {
        return JSONB.IO.writeInt32(bytes, off, symbol);
    }

    off = writeString(bytes, off, typeName);
    return writeInt32(bytes, off, symbol);
}

public void writeString(List<String> list) {
    if (list == null) {
        writeArrayNull();
        return;
    }

    final int size = list.size();
    startArray(size);

    if (STRING_VALUE != null && STRING_CODER != null) {
        int off = this.off;
        byte[] bytes = this.bytes;
        final int LATIN = 0;
        boolean latinAll = true;
        for (int i = 0; i < size; i++) {
            String str = list.get(i);
            if (str == null) {
                if (off == bytes.length) {
                    bytes = grow(off + 1);
                }
                bytes[off++] = BC_NULL;
                continue;
            }
            int coder = STRING_CODER.applyAsInt(str);
            if (coder != LATIN) {
                latinAll = false;
                break;
            }
            byte[] value = STRING_VALUE.apply(str);
            if (off + value.length + 6 >= bytes.length) {
                bytes = grow(off + value.length + 6);
            }
            off = JSONB.IO.writeStringLatin1(bytes, off, value);
        }
        if (latinAll) {
            this.off = off;
            return;
        }
    }

    for (int i = 0; i < size; i++) {
        writeString(
                list.get(i)
        );
    }
}

