public static BiFunction createBiFunction(Constructor constructor) {
    try {
        Class<?> declaringClass = constructor.getDeclaringClass();
        MethodHandles.Lookup lookup = JDKUtils.trustedLookup(declaringClass);
        Class<?>[] parameterTypes = constructor.getParameterTypes();
        Class<?> param0 = parameterTypes[0];
        Class<?> param1 = parameterTypes[1];

        MethodHandle methodHandle = lookup.findConstructor(
                declaringClass,
                MethodType.methodType(void.class, param0, param1)
        );

        CallSite callSite = LambdaMetafactory.metafactory(
                lookup,
                "apply",
                METHOD_TYPE_BI_FUNCTION,
                METHOD_TYPE_OBJECT_OBJECT_OBJECT,
                methodHandle,
                MethodType.methodType(declaringClass, box(param0), box(param1))
        );
        return (BiFunction) callSite.getTarget().invokeExact();
    } catch (Throwable ignored) {
        errorLast = ignored;
    }

    return new ConstructorBiFunction(constructor);
}

protected FieldWriterEnum(
        String name,
        int ordinal,
        long features,
        String format,
        Locale locale,
        String label,
        Type fieldType,
        Class<? extends Enum> enumClass,
        Field field,
        Method method,
        Function function
) {
    super(name, ordinal, features, format, locale, label, fieldType, enumClass, field, method, function);

    this.enumType = enumClass;
    this.enumConstants = enumClass.getEnumConstants();
    this.hashCodes = new long[enumConstants.length];
    this.hashCodesSymbolCache = new long[enumConstants.length];
    for (int i = 0; i < enumConstants.length; i++) {
        hashCodes[i] = Fnv.hashCode64(enumConstants[i].name());
    }

    valueNameCacheUTF8 = new byte[enumConstants.length][];
    valueNameCacheUTF16 = new char[enumConstants.length][];

